INSERT INTO public.site_visits (id, estimate_id, visit_date, visitor_name, visit_purpose, visit_status, visit_result, site_memo, risk_memo, next_action, created_at) VALUES
('visit-uuid-001', 'est-uuid-001', '2025-12-08', '김철수 부장', '배관 노후화 및 누설점 실측', '완료', '3라인 메인 파이프 하단 200mm 균열 심화 확인. SUS304 스케줄 10 자재 제안.', '천장 배관 지지 빔 앵커 부식 있음. 지지대 보강 시공 WBS 추가 요망.', '고소작업차 진입을 위해 공정 로터리 일부 철거 협의됨.', '12월 10일까지 최종 ISO 상세도면 및 견적 WBS 작성 송부.', '2025-12-05 09:30:00+00'),
('visit-uuid-002', 'est-uuid-002', '2025-12-24', '홍길동 대표', '초순수 DIW 루프 연결 정밀 치수 검사', '완료', '크린룸 Class 100 기준 충족. EP 가공 배관 용접 시 퍼지 시간 확보 가능 확인.', '배양기 전단 분접구 협소. 스윙 체크 밸브 배치 동선 변경 요구.', '공정 중단Tie-in을 위한 주말 10시간 정전 한계 확인.', '용접 품질 보증서 및 시나리오 송부.', '2025-12-20 10:15:00+00'),
('visit-uuid-003', 'est-uuid-003', '2026-01-13', '김철수 부장', '황산 유하 배관 화학 부식 분석', '완료', '황산 잔류로 인한 강도 저하 우려 확인. PTFE 테플론 라인 적용 제안 결정.', '용접 포인트 최소화 필요. 기성 플랜지 이음 구간 실측.', '독성 유체 배출을 위한 안전 가스 퍼지 가이드라인 설계 요구.', '1월 15일까지 PTFE 라이닝 관 사양서 견적 작성.', '2026-01-10 14:20:00+00'),
('visit-uuid-004', 'est-uuid-004', '2026-01-21', '이영희 대리', '물류센터 천장 메인 소화관 동파 실측', '완료', '150m 구간 보온재 완전 탈락 상태 확인. 메탈 열선 1.5w/m 설계 적합.', '천장 높이 8.5m로 시저스 리프트 반입 경로 확인 완료.', '겨울철 최저 영하 12도 감안하여 메탈히터 릴레이 이중화 권장.', '견적서 작성 및 수주 품의 지원.', '2026-01-18 11:00:00+00'),
('visit-uuid-005', 'est-uuid-006', '2026-02-24', '홍길동 대표', '대형 매니폴더 Hot-tapping 가능성 진단', '완료', '기존 배관 진원도 99%로 핫태핑 피팅 슬리브 안착 가능 진단.', '12시간 셧다운 내 매니폴더 4개 탭 천공 가능 타임라인 조율.', '차단 시 배관 물 빼기 드레인 밸브 개방 한계 협의.', '천공 장비 수급 및 WBS 송부.', '2026-02-20 16:00:00+00'),
('visit-uuid-006', 'est-uuid-007', '2026-03-09', '김철수 부장', '고압 가스 공급부 진동 주파수 실측', '완료', '펌프 기동 시 25Hz 대역 진동 증폭. 유연 플렉시블 조인트 2단 적용 제안.', '기계실 펌프 흡입 편심관 리듀서 재설계 필요성 전달함.', '방진 스프링 베이스 하단 패드 신설 공간 필요.', '3D ISO 간섭 검토 뷰 도면 작성.', '2026-03-05 13:30:00+00'),
('visit-uuid-007', 'est-uuid-009', '2026-04-05', '이영희 대리', '클린룸 질소 배관 분접 여건 실측', '완료', 'Class 100 무균실 가스 분기 라인 이물 차단 구조 확인.', 'EP 자재 보관을 위한 클린 텐트 설치 공간 조율.', '산소 농도 경보기 설치 필요성 식별.', '견적서 및 자재 리스트 발송.', '2026-04-02 14:00:00+00'),
('visit-uuid-008', 'est-uuid-012', '2026-04-25', '김철수 부장', '칠러 기계실 바이패스관 레이아웃 스캔', '완료', '기존 관경 80A 밸브 노후 확인. 신속한 차단 바이패스관 65A 스펙 확정.', '작업 구간 기계실 출입구 폭 900mm로 대형 조립품 반입 불가 확인. 현장 조립 필요.', NULL, 'WBS 견적 산정.', '2026-04-22 09:30:00+00'),
('visit-uuid-009', 'est-uuid-015', '2026-05-04', '김철수 부장', '난방 스팀 분기 헤더 플랜지 누수 진단', '완료', '스팀 플랜지 체결 볼트 부식 절단 상태. 볼트 전면 교체 및 고온 가스켓 대체 진단.', '주민 소음 차단을 위해 주간 작업 시간 10시~17시 엄격 제한 확인.', NULL, '긴급 견적서 산출 완료.', '2026-05-02 13:00:00+00'),
('visit-uuid-010', 'est-uuid-016', '2026-05-08', '김철수 부장', '솔벤트 공급 메인 분기 씰 실측', '완료', '방폭 규정 적용 구간. 비불꽃(방폭 전용) 유압 코킹 장비 사용 공법 수립.', NULL, '방폭 구역 가스 측정기 의무 휴대 교육 배정 필요.', '방폭 시공 계획서 작성 및 견적 대장 수립.', '2026-05-05 09:30:00+00')
